window.__QUIZ_DATA__=[{"id":"objective>Commerce>1996>1","subject":"Commerce","year":"1996","type":"Objective","topic":"ELEMENTS OF BUSINESS MANAGEMENT : BUSINESS RESOURCES","question":"Which of the following is not the duty of an entrepreneur?","images":[],"options":{"A":"provision of initial capital","B":"bearing of risks","C":"organization of other factors of production","D":"decision on the amount of tax pay"},"answer":"D","explanation":"An entrepreneur is responsible for the provision of initial capital, bearing of risks, and organization of other factors of production. However, the decision on the amount of tax to pay is not the duty of an entrepreneur. This is usually determined by the government's tax regulations and policies.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1996>2","subject":"Commerce","year":"1996","type":"Objective","topic":"TRADE : BALANCE OF PAYMENT","question":"The difference between the total amount of money received by a country and the total amount paid to other countries within a given period is the","images":[],"options":{"A":"trade gap","B":"balance of trade","C":"balance of payments","D":"current account balance"},"answer":"B","explanation":"The difference between the total amount of money received by a country and the total amount paid to other countries within a given period is referred to as the balance of trade. The balance of trade is a significant part of a country's balance of payments. It is the largest component of a country's balance of payments. It is the difference between a country's exports and its imports. If a country exports more than it imports, it has a trade surplus. If it imports more than it exports, it has a trade deficit.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>1996>3","subject":"Commerce","year":"1996","type":"Objective","topic":"AIDS TO TRADE: COMMUNICATION : TYPES","question":"Which of the following is used to transmit typed messages over long distances?","images":[],"options":{"A":"Dictaphone","B":"Teleprinter","C":"Computer","D":"Telephone"},"answer":"B","explanation":"A teleprinter is a telecommunication device that can be used to send and receive typed messages from point to point and point-to-multipoint over various types of communications channels. They were adapted to provide a user interface to early mainframe computers and minicomputers, sending typed data to the computer and printing the response. Some models could also be used to create punched tape for data storage (either from typed input or from data received from a remote source) and to read back such tape for local printing or transmission.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1996>4","subject":"Commerce","year":"1996","type":"Objective","topic":"BUSINESS UNIT: MERGER : MEANING AND TYPES OF MERGER","question":"When a company buys up firms supplying it with raw materials, this is an example of","images":[],"options":{"A":"horizontal integration","B":"a holding company","C":"backward integration","D":"consortium"},"answer":"C","explanation":"Backward integration is a type of vertical integration that includes the purchase of, or merger with, suppliers. Companies pursue backward integration when it is expected to result in improved efficiency and cost savings. For example, a bakery might buy a wheat processor or a wheat farm to have a ready and cheap supply of wheat flour. Therefore, when a company buys up firms supplying it with raw materials, it is an example of backward integration.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>1996>5","subject":"Commerce","year":"1996","type":"Objective","topic":"OCCUPATION : TYPES OF OCCUPATION","question":"Industrial, commercial and direct services are branches of","images":[],"options":{"A":"manufacturing","B":"occupation","C":"exchange","D":"distribution"},"answer":"B","explanation":"Industrial, commercial and direct services are branches of occupation. Occupation refers to the regular activity performed by people to earn a living. It is broadly classified into three categories: business, employment, and profession. Business can be further divided into industry, commerce, and direct services. Industry involves the production of goods and materials, while commerce is concerned with the exchange of goods and services from the producer to the final consumer. Direct services refer to the services provided directly to the consumer like teaching, doctor, lawyer etc.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1996>6","subject":"Commerce","year":"1996","type":"Objective","topic":"BUSINESS CAPITAL, PROFIT AND TURNOVER : SOURCE OF FINANCE","question":"The primary purpose of credit cards is to","images":[],"options":{"A":"obtain goods without paying cash on the spot","B":"obtain a loan from the bank","C":"obtain a loan from a trader","D":"persuade a business man to cash a cheque"},"answer":"A","explanation":"The primary purpose of credit cards is to obtain goods without paying cash on the spot. A credit card is a payment card issued to users to enable the cardholder to pay a merchant for goods and services based on the cardholder's promise to the card issuer to pay them for the amounts plus the other agreed charges. The card issuer (usually a bank) creates a revolving account and grants a line of credit to the cardholder, from which the cardholder can borrow money for payment to a merchant or as a cash advance.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1996>7","subject":"Commerce","year":"1996","type":"Objective","topic":"AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION","question":"Containers are suitable for transporting goods by","images":[],"options":{"A":"sea only","B":"road only","C":"sea and rail only","D":"road, sea and rail"},"answer":"D","explanation":"Containers are versatile in their usage for transportation. They can be used for transporting goods by road, sea, and rail. This is because containers are designed to be moved from one mode of transport to another without unloading and reloading the contents. This is known as intermodal transport.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1996>8","subject":"Commerce","year":"1996","type":"Objective","topic":"MONEY : MEANING AND TYPES OF MONEY","question":"Which of the following is not a credit instrument used in business transactions?","images":[],"options":{"A":"Luncheon voucher","B":"Bill of exchange","C":"Promissory note","D":"Fuel voucher"},"answer":"A","explanation":"A luncheon voucher is not a credit instrument used in business transactions. It is a type of meal ticket. On the other hand, a bill of exchange and a promissory note are both credit instruments. A bill of exchange is a binding agreement by one party to pay a fixed amount of cash to another party on demand or at a predetermined date. A promissory note is a financial instrument that contains a written promise by one party to pay another party a definite sum of money either on demand or at a specified future date. A fuel voucher is a type of voucher that can be exchanged for fuel.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1996>9","subject":"Commerce","year":"1996","type":"Objective","topic":"AIDS TO TRADE: INSURANCE : PRINCIPLES","question":"An insurance company shares its accepted risk with others in the form of","images":[],"options":{"A":"reinsurance","B":"subrogation","C":"mutual insurance","D":"fidelity guarantee insurance"},"answer":"A","explanation":"Reinsurance is a practice where an insurance company reduces its possible maximum loss by obtaining insurance from another insurer to carry part of the risk. This is done to share the accepted risk with others. Subrogation, mutual insurance, and fidelity guarantee insurance do not involve sharing of risk with others.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>1996>10","subject":"Commerce","year":"1996","type":"Objective","topic":"ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE","question":"Which of the following stresses the use of only specialists to head departments?","images":[],"options":{"A":"Committee organisation structure","B":"Line organisation structure","C":"line and staff organisation structure","D":"Functional organisation structure"},"answer":"D","explanation":"A functional organization structure is a type of organizational structure where the organization is divided into smaller groups based on specialized functional areas, such as IT, finance, or marketing. This structure emphasizes the use of specialists to head departments. The other options, such as Committee organisation structure, Line organisation structure, and line and staff organisation structure, do not necessarily stress the use of only specialists to head departments.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>1996>11","subject":"Commerce","year":"1996","type":"Objective","topic":"BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES","question":"The process of involving local businessmen in the ownership and control of businesses that were formerly owned by foreigners is called","images":[],"options":{"A":"nationalization","B":"industrialization","C":"indeginization","D":"commercialization"},"answer":"C","explanation":"Indigenization is the process of involving local businessmen in the ownership and control of businesses that were formerly owned by foreigners. Nationalization refers to the process of a government taking control of a company or industry, which can occur for a variety of reasons. Industrialization is the process by which an economy is transformed from primarily agricultural to one based on the manufacturing of goods. Commercialization is the process of introducing a new product or production method into commerce\u2014making it available on the market.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1996>12","subject":"Commerce","year":"1996","type":"Objective","topic":"TRADE : HOME TRADE: RETAIL TRADE","question":"Which of the following functions is not performed by retailers?","images":[],"options":{"A":"Breaking bulk","B":"Ensuring regular stock for consumers","C":"Branding and packaging","D":"Insuring goods for customers"},"answer":"D","explanation":"Retailers perform a variety of functions including breaking bulk (dividing larger quantities of goods into smaller lots), ensuring regular stock for consumers, and sometimes even branding and packaging. However, insuring goods for customers is typically not a function performed by retailers. This is usually done by insurance companies or is the responsibility of the customer themselves.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1996>13","subject":"Commerce","year":"1996","type":"Objective","topic":"ELEMENTS OF BUSINESS MANAGEMENT : PRINCIPLE","question":"Which of these management functions involves checking performance against set standards?","images":[],"options":{"A":"Controlling","B":"Coordinating","C":"Planning","D":"Directing"},"answer":"A","explanation":"Controlling is the management function that involves checking performance against set standards. It involves measuring actual performance, comparing this with set standards, and taking corrective action if necessary. This is to ensure that the organization's plans are being implemented correctly and to see if goals are being achieved.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1996>14","subject":"Commerce","year":"1996","type":"Objective","topic":"TRADE : DOCUMENT USED IN INTERNATIONAL TRADE","question":"The form given by the Customs Authority to enable an importer examine goods before the arrival of the bill of lading is known as","images":[],"options":{"A":"entry for warehousing","B":"certificate of origin","C":"bill of sight","D":"bill of exchange"},"answer":"C","explanation":"A bill of sight is a document given by the Customs Authority to enable an importer examine goods before the arrival of the bill of lading. It is a temporary document that allows the goods to be inspected before the actual documents arrive. This is to ensure that the goods are as described and meet the required standards.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>1996>15","subject":"Commerce","year":"1996","type":"Objective","topic":"BUSINESS UNIT: PUBLIC CORPORATION : ADVANTAGES AND DISADVANTAGES","question":"An organization that builds access roads for the benefit of the community in which it is located has fulfilled its","images":[],"options":{"A":"legal responsibility","B":"political responsibility","C":"social responsibility","D":"technological responsibility"},"answer":"C","explanation":"Social responsibility refers to the ethical framework which suggests that an entity, be it an organization or individual, has an obligation to act for the benefit of society at large. In this case, building access roads for the benefit of the community is a form of social responsibility.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1996>16","subject":"Commerce","year":"1996","type":"Objective","topic":"TRADE : FOREIGN TRADE","question":"Which of the following is applicable to foreign trade only?","images":[],"options":{"A":"Pro forma invoice","B":"insurance policy","C":"Order","D":"Consular invoice"},"answer":"D","explanation":"A consular invoice is a document, often used in foreign trade, that is required by some foreign countries. It is used as a control measure to ensure the quality and value of goods shipped, and it is issued by the consul of the country the goods are being shipped to. Therefore, it is applicable to foreign trade only.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1996>17","subject":"Commerce","year":"1996","type":"Objective","topic":"ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE","question":"The department that deals with internal grievances and maintenance of discipline in an organization is the","images":[],"options":{"A":"accounts","B":"maintenance","C":"personnel","D":"public relations"},"answer":"C","explanation":"The personnel department in an organization is responsible for dealing with internal grievances and maintaining discipline. This department is also known as the human resources department. It handles issues related to employees such as hiring, compensation, performance management, organization development, safety, wellness, benefits, employee motivation, communication, administration, and training.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1996>18","subject":"Commerce","year":"1996","type":"Objective","topic":"AIDS TO TRADE: TRANSPORTATION : DOCUMENT USED IN TRANSPORTATION","question":"Another name for consignment note is","images":[],"options":{"A":"qoutation","B":"waybill","C":"debit note","D":"receipt"},"answer":"B","explanation":"A consignment note is also known as a waybill. It is a document issued by a carrier giving details and instructions relating to the shipment of a consignment of goods. Typically it will show the names of the consignor and consignee, the point of origin of the consignment, its destination, and route.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1996>19","subject":"Commerce","year":"1996","type":"Objective","topic":"PRODUCTION : DIVISION OF LABOUR & SPECIALISATION","question":"Specialization is possible as a result of","images":[],"options":{"A":"good roads","B":"education","C":"demand for goods","D":"exchange"},"answer":"D","explanation":"Specialization is possible as a result of exchange. Specialization refers to the concept where a nation or an individual concentrates its productive efforts on producing a limited variety of goods. It is based on the principle of 'division of labor' where tasks are divided among different people according to their expertise. This is possible only when there is an exchange mechanism in place that allows the trading of goods and services. Therefore, the correct answer is 'exchange'.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1996>20","subject":"Commerce","year":"1996","type":"Objective","topic":"ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE","question":"Use the chart below to answer the questions     ORGANIZATIONAL CHART OF OLUWA PLC         In which of the boxes in the organization chart would you locate the shareholders of OLUWA PLC?","images":["data:image/png;base64,"],"options":{"A":"F","B":"X","C":"V","D":"T"},"answer":"D","explanation":"When a corporation is initially incorporated, the original owners are routinely the first shareholders. Therefore, T represent the shareholders of the company.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1996>21","subject":"Commerce","year":"1996","type":"Objective","topic":"ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE","question":"Use the chart below to answer the questions     ORGANIZATIONAL CHART OF OLUWA PLC       The position of the departmental manager would be located in box","images":["data:image/png;base64,"],"options":{"A":"T","B":"F","C":"W","D":"X"},"answer":"D","explanation":"In smaller businesses, the initial owners remain the sole shareholders throughout the life of the corporation. Employees, managers, and owners may all be stockholders in the company where they handle the daily operations of the business. Therefore, X represent the departmental manager of the company","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1996>22","subject":"Commerce","year":"1996","type":"Objective","topic":"ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE","question":"Use the chart below to answer the questions     ORGANIZATIONAL CHART OF OLUWA PLC       The bond of directors of Oluwa plc would be in Box","images":["data:image/png;base64,"],"options":{"A":"V","B":"W","C":"X","D":"U"},"answer":"D","explanation":"Company's director represents the will and wants of the shareholders. They are notably known to act in the place of the shareholders and their goals. Therefore, U represent the bond of directors.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1996>23","subject":"Commerce","year":"1996","type":"Objective","topic":"ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE","question":"Use the chart below to answer the questions     ORGANIZATIONAL CHART OF OLUWA PLC       The position of the accounts clerk would be located in box","images":["data:image/png;base64,"],"options":{"A":"F","B":"T","C":"V","D":"U"},"answer":"A","explanation":"An accounting clerk is a member of a company's accounting department, responsible for assisting with both clerical and administrative tasks. In general, an accounting clerk takes care of basic office tasks that involve reporting, bookkeeping, research, as well as the resolution of discrepancies related to any of the tasks he or she performs. F represent the position of an account clerk of the organization.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1996>24","subject":"Commerce","year":"1996","type":"Objective","topic":"ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE","question":"Use the chart below to answer the questions     ORGANIZATIONAL CHART OF OLUWA PLC       The managing director would be located in box","images":["data:image/png;base64,"],"options":{"A":"V","B":"T","C":"U","D":"W"},"answer":"A","explanation":"A company's managing director does the following work: Manages the company's budget and allocates its resources. Create strategic business plans for meeting the company's goals. V represent the position for a managing director.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1996>25","subject":"Commerce","year":"1996","type":"Objective","topic":"ELEMENTS OF BUSINESS MANAGEMENT : ORGANIZATIONAL STRUCTURE","question":"Use the chart below to answer the questions     ORGANIZATIONAL CHART OF OLUWA PLC       which of the following is represented by the chart?","images":["data:image/png;base64,"],"options":{"A":"committee organization","B":"staff organization","C":"line and staff organization","D":"line organization"},"answer":"C","explanation":"Line and staff organization is the organization structure, in which there is a normal departmentation of the regular business operations, and there is the functional specialist to perform specialised activities. While line authority relies on command, line and staff authority is based on command and advise.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1996>26","subject":"Commerce","year":"1996","type":"Objective","topic":"PURCHASES AND SALES OF GOODS : DOCUMENT USED IN BUYING & SELLING","question":"Which of the following may serve as delivery note?","images":[],"options":{"A":"Debit note","B":"Credit note","C":"Invoice","D":"Advice note"},"answer":"D","explanation":"A delivery note may serve as an Advice note. A delivery note is a document that is included with a shipment of goods sent out to a customer. It lists the description and amount of goods delivered. An advice note is a written piece of communication often included with a shipment of goods that provides details about the delivery. The advice note can also serve as proof of delivery. Therefore, the correct answer is 'Advice note'.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1996>27","subject":"Commerce","year":"1996","type":"Objective","topic":"AIDS TO TRADE: INSURANCE : PRINCIPLES","question":"Mr Chidi insured his house against fire. The house was destroyed by flood. Which of the following principles prevented him from being compensated?","images":[],"options":{"A":"Uberrimae fidei","B":"Subrogation","C":"Indemnity","D":"Proximate cause"},"answer":"D","explanation":"The principle of Proximate Cause in insurance states that the loss of an insured risk must be caused by the risk insured against. In this case, Mr Chidi insured his house against fire, but the house was destroyed by flood, which is a different risk. Therefore, the principle of Proximate Cause prevents him from being compensated.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>1996>28","subject":"Commerce","year":"1996","type":"Objective","topic":"AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION","question":"The price charged for leasing a ship is known as","images":[],"options":{"A":"way bill","B":"haulage","C":"clean bill","D":"freight"},"answer":"D","explanation":"Freight is the term used to describe the price charged for transporting goods by sea or waterway, which includes leasing a ship. Therefore, the price charged for leasing a ship is known as freight.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1996>29","subject":"Commerce","year":"1996","type":"Objective","topic":"AIDS TO TRADE: WAREHOUSING: : TYPES & IMPORTANCE","question":"Goods in bonded warehouses are under the strict supervision of the","images":[],"options":{"A":"Customs Authority","B":"Ports Authority","C":"Importer","D":"Clearing agent"},"answer":"A","explanation":"Goods in bonded warehouses are under the strict supervision of the Customs Authority. A bonded warehouse is a secured area where imported goods are stored until the import duties are paid. These warehouses are under the control and supervision of the Customs Authority to ensure that the import duties are paid before the goods are released.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1996>30","subject":"Commerce","year":"1996","type":"Objective","topic":"STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS","question":"Which of the following regulates and controls the activities of the Nigerian Stock Exchange?","images":[],"options":{"A":"The Nigerian Capital Market Association","B":"The Securities and Exchange Commission","C":"The Nigerian Deposit Insurance Commission","D":"The Nigerian Reinsurance Corporation"},"answer":"B","explanation":"The Securities and Exchange Commission regulates and controls the activities of the Nigerian Stock Exchange. The Securities and Exchange Commission (SEC) is the main regulatory institution of the Nigerian capital market. It is supervised by the Federal Ministry of Finance. The main function of the SEC is to oversee the Nigerian Stock Exchange to ensure orderly and equitable dealings in securities, and protect the market against insider trading abuses.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>1996>31","subject":"Commerce","year":"1996","type":"Objective","topic":"BUSINESS UNIT: PARTNERSHIP : MEANING AND TYPES","question":"Which of the following is drawn up as a guide to the running of a Partnership?","images":[],"options":{"A":"Deed of Agreement","B":"Partnership Act","C":"Memorandum of Association","D":"Prospectus"},"answer":"A","explanation":"A Deed of Agreement is drawn up as a guide to the running of a Partnership. This document outlines the rights, responsibilities, and obligations of each partner in the partnership. It is a legally binding document that is used to manage disputes, disagreements, and other issues that may arise in the course of the partnership. The Partnership Act is a law that governs partnerships, but it is not drawn up by the partners themselves. The Memorandum of Association and the Prospectus are documents related to a company, not a partnership.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1996>32","subject":"Commerce","year":"1996","type":"Objective","topic":"BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES","question":"The law governing the operations of companies and partnership in Nigeria is the","images":[],"options":{"A":"Nigerian Companies Decree","B":"Nigerian Partnership Act","C":"Nigerian Enterprises Promotion Decree","D":"Companies And Allied Matters Decree"},"answer":"D","explanation":"The law governing the operations of companies and partnerships in Nigeria is the Companies And Allied Matters Decree. This law provides the legal framework for the formation, management, and winding up of companies and partnerships. The Nigerian Companies Decree and the Nigerian Partnership Act do not exist, while the Nigerian Enterprises Promotion Decree is related to the promotion of Nigerian enterprises, not the operations of companies and partnerships.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1996>33","subject":"Commerce","year":"1996","type":"Objective","topic":"AIDS TO TRADE: INSURANCE : TYPES","question":"Which of the following is a non-indemnity insurance?","images":[],"options":{"A":"Personal Accident Insurance","B":"Burglary Insurance","C":"Fire Insurance","D":"Consequential loss Insurance"},"answer":"A","explanation":"Non-indemnity insurance is a type of insurance where the insured is paid a specified amount regardless of the actual loss suffered. Personal Accident Insurance is a type of non-indemnity insurance because the insured is paid a specified amount in the event of an accident, regardless of the actual loss suffered.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>1996>34","subject":"Commerce","year":"1996","type":"Objective","topic":"BUSINESS UNIT: LIMITED LIABILITY COMPANIES : MEANING AND TYPES","question":"The document issued to a newly formed public company to commence business is called the","images":[],"options":{"A":"certificate of incorporation","B":"articles of association","C":"memorandum of association","D":"trading certificate"},"answer":"D","explanation":"A trading certificate is a document issued by the registrar of companies to a public company, allowing it to commence business. This is after the company has met certain requirements, including having a certain minimum amount of share capital. The certificate of incorporation, articles of association, and memorandum of association are all documents that are part of the process of forming a company, but they do not give the company the right to commence business.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1996>35","subject":"Commerce","year":"1996","type":"Objective","topic":"TRADE : HOME TRADE: RETAIL TRADE","question":"Small scale retail attracts a lot of new entrepreneurs in West Africa because","images":[],"options":{"A":"many people have had good training in retail trade","B":"it is easy to succeed with the business","C":"banks are always ready to lend retailers","D":"only a small amount of capital is needed to start the business"},"answer":"D","explanation":"Small scale retail attracts a lot of new entrepreneurs in West Africa because it requires only a small amount of capital to start the business. This is because the cost of setting up a small scale retail business is relatively low compared to other types of businesses. This makes it an attractive option for new entrepreneurs who may not have a lot of capital to invest.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1996>36","subject":"Commerce","year":"1996","type":"Objective","topic":"AIDS TO TRADE: INSURANCE : TERMS","question":"In marine insurance, the deliberate throwing of some goods into the sea to prevent the ship from sinking is an example of","images":[],"options":{"A":"a constructive loss","B":"a partial loss","C":"a general average loss","D":"a total loss"},"answer":"C","explanation":"In marine insurance, the deliberate throwing of some goods into the sea to prevent the ship from sinking is an example of a general average loss. A general average loss refers to a loss that occurs when a deliberate act is performed to save the vessel, cargo, or both from a common peril. In this case, the act of throwing goods into the sea is done to lighten the ship and prevent it from sinking, which is a common peril.","marks":"1","difficulty":"3"},{"id":"objective>Commerce>1996>37","subject":"Commerce","year":"1996","type":"Objective","topic":"TRADE : CUSTOMS, EXCISE, PORTS AUTHORITY ETC.","question":"Tax levied on goods at each stage of their movement from production to the final consumer is known as","images":[],"options":{"A":"customs drawback","B":"ad valorem duty","C":"specific tax","D":"value added tax"},"answer":"D","explanation":"Value Added Tax (VAT) is a type of tax that is assessed incrementally. It is levied at each stage of the production and distribution process and is based on the value added to the product at each stage. This is different from other types of taxes which are levied on the total value of the product or service at one stage.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1996>38","subject":"Commerce","year":"1996","type":"Objective","topic":"TRADE ASSOCIATION : CHAMBER OF COMMERCE","question":"An association of businessmen engaged in both commerce and industry is called","images":[],"options":{"A":"trade association","B":"Trade union","C":"chamber of commerce","D":"trust"},"answer":"C","explanation":"A Chamber of Commerce is a form of business network, e.g., a local organization of businesses whose goal is to further the interests of businesses. Business owners in towns and cities form these local societies to advocate on behalf of the business community. They are not a trade union (which is an organization of workers who have come together to achieve common goals such as protecting the integrity of its trade, improving safety standards, etc.), a trade association (which is an organization founded and funded by businesses that operate in a specific industry), or a trust (which is a fiduciary relationship in which one party, known as a trustor, gives another party, the trustee, the right to hold title to property or assets for the benefit of a third party).","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1996>39","subject":"Commerce","year":"1996","type":"Objective","topic":"BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES","question":"When the government decides to run a statutory corporation as a profit-oriented enterprise, this is known as","images":[],"options":{"A":"nationalization","B":"commercialization","C":"take-over bid","D":"privatization"},"answer":"B","explanation":"Commercialization is the process of managing or running something principally for financial gain. When the government decides to run a statutory corporation as a profit-oriented enterprise, it is commercializing that corporation. Nationalization is the process of transforming private assets into public assets by bringing them under the public ownership of a national government or state. A take-over bid is a type of corporate action in which an acquiring company makes an offer to the target company's shareholders to buy the target company's shares. Privatization is the process of transferring an enterprise or industry from the public sector to the private sector.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1996>40","subject":"Commerce","year":"1996","type":"Objective","topic":"INTRODUCTION TO COMMERCE : MEANING & SCOPE","question":"The primary aim of commerce is to","images":[],"options":{"A":"produce goods and services","B":"warehouse goods","C":"advertise goods and services","D":"exchange goods and services"},"answer":"D","explanation":"The primary aim of commerce is to exchange goods and services. Commerce is the conduct of trade among economic agents. Generally, commerce refers to the exchange of goods, services or something of value, between businesses or entities. Producing goods and services is the role of production, not commerce. Warehousing goods is a part of the distribution aspect of commerce, but not its primary aim. Advertising goods and services is a part of the promotion aspect of commerce, but not its primary aim.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1996>41","subject":"Commerce","year":"1996","type":"Objective","topic":"STOCK EXCHANGE : TYPES OF SECURITIES","question":"Which of the following has a fixed rate of dividend?","images":[],"options":{"A":"Debenture","B":"Ordinary share","C":"Founder's share","D":"Preference share"},"answer":"D","explanation":"Preference shares have a fixed rate of dividend. This means that the dividends paid to preference shareholders are a fixed percentage of the nominal value of the shares. This is unlike ordinary shares where dividends can fluctuate based on the company's profits.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1996>42","subject":"Commerce","year":"1996","type":"Objective","topic":"ECONOMIC GROUPING : MEANING AND TYPES SUCH AS ECOWAS, NIGER BASIN COM ETC.","question":"Which of the following is not a barrier to the smooth functioning of ECOWAS?","images":[],"options":{"A":"Different currencies","B":"Different languages","C":"Adequate population","D":"Political crisis"},"answer":"C","explanation":"Adequate population is not a barrier to the smooth functioning of ECOWAS. In fact, a large population can be beneficial as it provides a larger market for goods and services. Barriers to the smooth functioning of ECOWAS would include factors that hinder trade and cooperation such as different currencies, different languages, and political crises.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1996>43","subject":"Commerce","year":"1996","type":"Objective","topic":"STOCK EXCHANGE : MEANING, IMPORTANCE AND FUNCTIONS","question":"The capital market is a market","images":[],"options":{"A":"for long term loans","B":"for new shares of public companies","C":"where money is deposited","D":"where foreign currencies are bought and sold"},"answer":"A","explanation":"The capital market is a market for long-term loans. It is a market where individuals and institutions with surplus funds are linked with those requiring long-term financing. It is not primarily for new shares of public companies, nor is it a place where money is deposited or where foreign currencies are bought and sold.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1996>44","subject":"Commerce","year":"1996","type":"Objective","topic":"BUSINESS UNIT: PUBLIC CORPORATION : MEANING AND TYPES","question":"Which of the following is primarily established to promote the growth of industry in Nigeria?","images":[],"options":{"A":"NITEL","B":"UBA","C":"NIPOST","D":"NIDB"},"answer":"D","explanation":"The Nigerian Industrial Development Bank (NIDB) is primarily established to promote the growth of industry in Nigeria. It provides long-term financing to industrial enterprises. NITEL, UBA, and NIPOST are not primarily established for the growth of industry.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1996>45","subject":"Commerce","year":"1996","type":"Objective","topic":"AIDS TO TRADE: TRANSPORTATION : MEANING AND TYPES OF TRANSPORTATION","question":"Another name for sea taxi is","images":[],"options":{"A":"tramp","B":"liner","C":"special freighter","D":"voyage charter"},"answer":"A","explanation":"A sea taxi is also known as a tramp. A tramp is a ship that does not have a fixed schedule or published ports of call. Unlike a liner, which has a fixed schedule and routes, a tramp goes wherever the charterer decides, much like a taxi.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1996>46","subject":"Commerce","year":"1996","type":"Objective","topic":"AIDS TO TRADE: TRANSPORTATION : DOCUMENT USED IN TRANSPORTATION","question":"Contracts for the carriage of goods by sea are generally called","images":[],"options":{"A":"charter by demise","B":"charter parties","C":"voyage charters","D":"time charter"},"answer":"B","explanation":"Contracts for the carriage of goods by sea are generally called charter parties. A charter party is a legal term in shipping where a shipowner hires out their vessel to a charterer for a specific journey or a period of time. The charterer then has control over where the ship goes and what it carries. The other options, charter by demise, voyage charters, and time charter, are types of charter parties, but the general term for these contracts is charter parties.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1996>47","subject":"Commerce","year":"1996","type":"Objective","topic":"AIDS TO TRADE: TOURISM : TYPES & IMPORTANCE","question":"A nation's earnings from tourism are classified as","images":[],"options":{"A":"visible exports","B":"invisible exports","C":"visible imports","D":"invisible imports"},"answer":"B","explanation":"A nation's earnings from tourism are classified as 'invisible exports'. This is because they are part of the service sector and do not involve the physical movement of goods across borders. Therefore, they are not 'visible' in the traditional sense. The term 'export' is used because the service (in this case, tourism) is provided to foreign individuals or entities, bringing money into the country.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1996>48","subject":"Commerce","year":"1996","type":"Objective","topic":"TRADE ASSOCIATION : MEANING & FUNCTIONS","question":"An association of employees in an organization is called a","images":[],"options":{"A":"trade union","B":"trade association","C":"consumer association","D":"credit union"},"answer":"A","explanation":"An association of employees in an organization is called a 'trade union'. Trade unions are organizations that represent the interests of workers or employees in a particular industry or occupation. They negotiate with employers on issues such as wages, working conditions, and employment policies. Trade associations, on the other hand, represent the interests of businesses in a particular industry. Consumer associations represent the interests of consumers, and credit unions are cooperative financial institutions where members can borrow from pooled deposits at low interest rates.","marks":"1","difficulty":"1"},{"id":"objective>Commerce>1996>49","subject":"Commerce","year":"1996","type":"Objective","topic":"AIDS TO TRADE: INSURANCE : TERMS","question":"A firm that accepts a portion of the risk involved in an insurance contract is","images":[],"options":{"A":"a broker","B":"an actuary","C":"a speculator","D":"an underwriter"},"answer":"D","explanation":"An underwriter is a person or company that takes on the risk involved in an insurance contract. They assess the risk and exposure of potential clients and decide how much coverage the client should receive and how much they should pay for it. In this case, the firm that accepts a portion of the risk involved in an insurance contract is an underwriter.","marks":"1","difficulty":"2"},{"id":"objective>Commerce>1996>50","subject":"Commerce","year":"1996","type":"Objective","topic":"PURCHASES AND SALES OF GOODS : TERMS OF TRADE","question":"Musa places the bicycle for sale at #800.00 and Dada had agreed to pay the amount. In this transaction, Musa is the","images":[],"options":{"A":"offeror","B":"offeree","C":"buyer","D":"guarantor"},"answer":"A","explanation":"In a sales transaction, the person who places the item for sale is known as the offerer or seller. They are the ones who make the offer which the other party can accept or reject. In this case, Musa is the offerer because he is the one who placed the bicycle for sale.","marks":"1","difficulty":"2"}];